// =====================================================
// Peak Day - Full Function (330 messages exactly)
// Node-RED Function Node
// Output 1 = { payload: messages, summary, compliance, energy_inputs }
// =====================================================

// ------------------------------
// Config
// ------------------------------
let nowMs = Date.now();
let lastMs = flow.get("lastInjectMs") || nowMs;
let intervalSec = (nowMs - lastMs) / 1000;
flow.set("lastInjectMs", nowMs);

if (intervalSec <= 0) intervalSec = 1;

// ------------------------------
// Helpers
// ------------------------------
function clamp(val, min, max) {
    return Math.max(min, Math.min(max, val));
}

function pushMsg(arr, topic, device, point, value, extra = {}) {
    arr.push({
        topic: topic,
        payload: JSON.stringify({
            timestamp: new Date().toISOString(),
            device: device,
            point: point,
            value: Number(value),
            ...extra
        })
    });
}

function getValue(messages, topic) {
    const item = messages.find(m => m.topic === topic);
    return item ? JSON.parse(item.payload).value : null;
}

function avg(arr) {
    if (!arr || arr.length === 0) return null;
    return arr.reduce((a, b) => a + b, 0) / arr.length;
}

function buildGroupSummary(messages, devices, points, topicBuilder) {
    const result = {};
    devices.forEach(deviceObj => {
        const devKey = deviceObj.key;
        result[devKey] = {};
        points.forEach(point => {
            result[devKey][point] = getValue(messages, topicBuilder(deviceObj, point));
        });
    });
    return result;
}

// ------------------------------
// Scenario preset: Peak Day
// ------------------------------
const scenario = "peak_day";
const scenarioLabel = "Peak Day - high occupancy, hot weather";

// Building / weather assumptions for Peak Day
const outdoorDryBulb = Number((35.2 + Math.random() * 1.5).toFixed(2));   // 35.2 - 36.7 C
const outdoorRH = Number((68 + Math.random() * 8).toFixed(2));            // 68 - 76 %RH
const outdoorWetBulb = Number((outdoorDryBulb - (2.5 + Math.random() * 1.5)).toFixed(2));

// Peak day => high load
const occupancyFactor = 0.92 + Math.random() * 0.03;
const weatherFactor = clamp(((outdoorDryBulb - 30) / 5) * 0.22, 0, 0.3);
const loadFraction = Number(clamp(
    occupancyFactor + weatherFactor + (Math.random() * 0.02 - 0.01),
    0.82,
    0.95
).toFixed(3));

// Plant capacity
const TOTAL_CAPACITY_RT = 1500;
const totalCoolingRT = Number((TOTAL_CAPACITY_RT * loadFraction).toFixed(2));

// Chiller staging for Peak Day => force 3 chillers
const activeChillers = 3;
const perChillerRT = Number((totalCoolingRT / activeChillers).toFixed(2));

// Specs
const CHILLER_RATED_RT = 500;
const CHILLER_RATED_KW = 273;

const CHWP_RATED_GPM = 1200;
const CHWP_RATED_KW = 37;

const CDP_RATED_GPM = 1500;
const CDP_RATED_KW = 55;

const CT_CELL_RATED_KW = 5.5; // 2 cells per tower
const AHU_COUNT = 4;
const VAV_COUNT = 16;
const IAQ_COUNT = 8;

// ------------------------------
// Containers
// ------------------------------
let messages = [];

let chillerPowers = [0, 0, 0];
let chwpPowers = [0, 0, 0];
let cdpPowers = [0, 0, 0];
let ctPowers = [0, 0, 0];
let ahuPowers = [0, 0, 0, 0];
let floorPowers = [0, 0, 0, 0];
let floorMeterPowers = [0, 0, 0, 0];
// ------------------------------
// 1) Outdoor Weather Station Points (3)
// ------------------------------
pushMsg(messages, "building/weather/1/drybulb_temperature", "weather_1", "drybulb_temperature", outdoorDryBulb, {
    group: "Outdoor Weather Station Points",
    floor: null
});
pushMsg(messages, "building/weather/1/humidity", "weather_1", "humidity", outdoorRH, {
    group: "Outdoor Weather Station Points",
    floor: null
});
pushMsg(messages, "building/weather/1/wetbulb_temperature", "weather_1", "wetbulb_temperature", outdoorWetBulb, {
    group: "Outdoor Weather Station Points",
    floor: null
});

// ------------------------------
// Common chilled water temps
// ------------------------------
const chwSupplyC = Number((6.1 + Math.random() * 0.6).toFixed(2));              // 6.1 - 6.7 C
const chwReturnC = Number((12.0 + Math.random() * 0.8).toFixed(2));             // 12.0 - 12.8 C
const deltaTC = Number((chwReturnC - chwSupplyC).toFixed(2));

const chwSupplyF = Number((chwSupplyC * 9 / 5 + 32).toFixed(2));
const chwReturnF = Number((chwReturnC * 9 / 5 + 32).toFixed(2));
const deltaTF = Number((deltaTC * 9 / 5).toFixed(2));

// ------------------------------
// 2) Chiller Monitoring Points (3 x 13 = 39)
// ------------------------------
for (let i = 1; i <= 3; i++) {
    const plr = clamp(perChillerRT / CHILLER_RATED_RT, 0.35, 1.0);

    // efficiency in kW/RT
    const efficiency = Number(clamp(
        0.53 + (1 - plr) * 0.10 + Math.random() * 0.02,
        0.52,
        0.68
    ).toFixed(3));

    const powerKW = Number(clamp(perChillerRT * efficiency, 150, CHILLER_RATED_KW).toFixed(2));
    const evapFlow = Number(clamp(
        1000 + plr * 180 + Math.random() * 20,
        1000,
        CHWP_RATED_GPM
    ).toFixed(2));
    const satRefrigTempF = Number(clamp(chwSupplyF - (6 + Math.random() * 2), 34, 40).toFixed(2));
    const approachTempF = Number(clamp(1.5 + Math.random() * 1.5, 1.5, 3.5).toFixed(2));
    const percentageRLA = Number((plr * 100).toFixed(2));
    const coolingRate = perChillerRT;
    const alarm = 0;

    chillerPowers[i - 1] = powerKW;

    const extra = {
        group: "Chiller Monitoring Points",
        floor: null,
        equipment_index: i
    };

    pushMsg(messages, `building/chiller/${i}/evap_leaving_water_temperature`, `chiller_${i}`, "evap_leaving_water_temperature", chwSupplyF, extra);
    pushMsg(messages, `building/chiller/${i}/evap_entering_water_temperature`, `chiller_${i}`, "evap_entering_water_temperature", chwReturnF, extra);
    pushMsg(messages, `building/chiller/${i}/evap_water_flow_rate`, `chiller_${i}`, "evap_water_flow_rate", evapFlow, extra);
    pushMsg(messages, `building/chiller/${i}/evap_sat_refrig_temperature`, `chiller_${i}`, "evap_sat_refrig_temperature", satRefrigTempF, extra);
    pushMsg(messages, `building/chiller/${i}/evap_water_delta_temperature`, `chiller_${i}`, "evap_water_delta_temperature", deltaTF, extra);
    pushMsg(messages, `building/chiller/${i}/evap_approach_temperature`, `chiller_${i}`, "evap_approach_temperature", approachTempF, extra);
    pushMsg(messages, `building/chiller/${i}/status_read`, `chiller_${i}`, "status_read", 1, extra);
    pushMsg(messages, `building/chiller/${i}/status_write`, `chiller_${i}`, "status_write", 1, extra);
    pushMsg(messages, `building/chiller/${i}/power`, `chiller_${i}`, "power", powerKW, extra);
    pushMsg(messages, `building/chiller/${i}/alarm`, `chiller_${i}`, "alarm", alarm, extra);
    pushMsg(messages, `building/chiller/${i}/percentage_rla`, `chiller_${i}`, "percentage_rla", percentageRLA, extra);
    pushMsg(messages, `building/chiller/${i}/efficiency`, `chiller_${i}`, "efficiency", efficiency, extra);
    pushMsg(messages, `building/chiller/${i}/cooling_rate`, `chiller_${i}`, "cooling_rate", coolingRate, extra);
}

// ------------------------------
// 3) Pump & Cooling Tower Points (9 x 7 = 63)
//    CHWP 1-3, CDP 1-3, CT 1-3
// ------------------------------
for (let i = 1; i <= 3; i++) {
    // CHWP
    const chwpFreq = Number(clamp(52 + Math.random() * 4, 50, 60).toFixed(2));
    const chwpPower = Number((CHWP_RATED_KW * Math.pow(chwpFreq / 60, 3)).toFixed(2));
    const chwpEff = Number((0.75 + Math.random() * 0.03).toFixed(3));
    chwpPowers[i - 1] = chwpPower;

    let extra = { group: "Pump & Cooling Tower Points", floor: null, equipment_index: i };
    pushMsg(messages, `building/chwp/${i}/status_read`, `chwp_${i}`, "status_read", 1, extra);
    pushMsg(messages, `building/chwp/${i}/status_write`, `chwp_${i}`, "status_write", 1, extra);
    pushMsg(messages, `building/chwp/${i}/alarm`, `chwp_${i}`, "alarm", 0, extra);
    pushMsg(messages, `building/chwp/${i}/frequency_read`, `chwp_${i}`, "frequency_read", chwpFreq, extra);
    pushMsg(messages, `building/chwp/${i}/frequency_write`, `chwp_${i}`, "frequency_write", chwpFreq, extra);
    pushMsg(messages, `building/chwp/${i}/power`, `chwp_${i}`, "power", chwpPower, extra);
    pushMsg(messages, `building/chwp/${i}/efficiency`, `chwp_${i}`, "efficiency", chwpEff, extra);

    // CDP
    const cdpFreq = Number(clamp(51 + Math.random() * 5, 50, 60).toFixed(2));
    const cdpPower = Number((CDP_RATED_KW * Math.pow(cdpFreq / 60, 3)).toFixed(2));
    const cdpEff = Number((0.73 + Math.random() * 0.03).toFixed(3));
    cdpPowers[i - 1] = cdpPower;

    pushMsg(messages, `building/cdp/${i}/status_read`, `cdp_${i}`, "status_read", 1, extra);
    pushMsg(messages, `building/cdp/${i}/status_write`, `cdp_${i}`, "status_write", 1, extra);
    pushMsg(messages, `building/cdp/${i}/alarm`, `cdp_${i}`, "alarm", 0, extra);
    pushMsg(messages, `building/cdp/${i}/frequency_read`, `cdp_${i}`, "frequency_read", cdpFreq, extra);
    pushMsg(messages, `building/cdp/${i}/frequency_write`, `cdp_${i}`, "frequency_write", cdpFreq, extra);
    pushMsg(messages, `building/cdp/${i}/power`, `cdp_${i}`, "power", cdpPower, extra);
    pushMsg(messages, `building/cdp/${i}/efficiency`, `cdp_${i}`, "efficiency", cdpEff, extra);

    // Cooling Tower
    const ctFreq = Number(clamp(45 + Math.random() * 6, 42, 60).toFixed(2));
    const ctPower = Number((CT_CELL_RATED_KW * Math.pow(ctFreq / 60, 3) * 2).toFixed(2)); // 2 cells
    const ctEff = Number((0.70 + Math.random() * 0.04).toFixed(3));
    ctPowers[i - 1] = ctPower;

    pushMsg(messages, `building/ct/${i}/status_read`, `ct_${i}`, "status_read", 1, extra);
    pushMsg(messages, `building/ct/${i}/status_write`, `ct_${i}`, "status_write", 1, extra);
    pushMsg(messages, `building/ct/${i}/alarm`, `ct_${i}`, "alarm", 0, extra);
    pushMsg(messages, `building/ct/${i}/frequency_read`, `ct_${i}`, "frequency_read", ctFreq, extra);
    pushMsg(messages, `building/ct/${i}/frequency_write`, `ct_${i}`, "frequency_write", ctFreq, extra);
    pushMsg(messages, `building/ct/${i}/power`, `ct_${i}`, "power", ctPower, extra);
    pushMsg(messages, `building/ct/${i}/efficiency`, `ct_${i}`, "efficiency", ctEff, extra);
}

// ------------------------------
// 4) Motorized Valve Points (4 x 3 = 12)
//    1 per AHU/floor
// ------------------------------
const zoneBias = [1.00, 1.02, 0.98, 1.01];

for (let floor = 1; floor <= 4; floor++) {
    const zoneLoad = clamp(loadFraction * zoneBias[floor - 1], 0.2, 1.0);

    // status_read / status_write are per spec table.
    // Here using valve % open as requested by description style
    const valveFeedback = Number(clamp(65 + zoneLoad * 25 + Math.random() * 4, 60, 98).toFixed(2));
    const valveCommand = Number(clamp(valveFeedback + (Math.random() * 4 - 2), 60, 98).toFixed(2));
    const valveAlarm = 0;

    const extra = {
        group: "Motorized Valve Points",
        floor: floor,
        equipment_index: floor
    };

    pushMsg(messages, `building/mv/${floor}/status_read`, `mv_${floor}`, "status_read", valveFeedback, extra);
    pushMsg(messages, `building/mv/${floor}/status_write`, `mv_${floor}`, "status_write", valveCommand, extra);
    pushMsg(messages, `building/mv/${floor}/alarm`, `mv_${floor}`, "alarm", valveAlarm, extra);
}

// ------------------------------
// 5) AHU Monitoring Points (4 x 7 = 28)
// ------------------------------
for (let floor = 1; floor <= 4; floor++) {
    const zoneLoad = clamp(loadFraction * zoneBias[floor - 1], 0.2, 1.0);

    const roomTemp = Number(clamp(23.7 + zoneLoad * 1.2 + (Math.random() * 0.4 - 0.2), 23.5, 25.5).toFixed(2));
    const setpoint = 23.0;
    const humidity = Number(clamp(58 + zoneLoad * 6 + Math.random() * 3, 58, 67).toFixed(2));
    const ahuAlarm = 0;
    const ahuPower = Number(clamp(12 + zoneLoad * 6 + Math.random() * 1.5, 12, 20).toFixed(2));

    ahuPowers[floor - 1] = ahuPower;
    floorPowers[floor - 1] += ahuPower;

    const extra = {
        group: "AHU Monitoring Points",
        floor: floor,
        equipment_index: floor
    };

    pushMsg(messages, `building/ahu/${floor}/room_temperature`, `ahu_${floor}`, "room_temperature", roomTemp, extra);
    pushMsg(messages, `building/ahu/${floor}/setpoint`, `ahu_${floor}`, "setpoint", setpoint, extra);
    pushMsg(messages, `building/ahu/${floor}/status_read`, `ahu_${floor}`, "status_read", 1, extra);
    pushMsg(messages, `building/ahu/${floor}/status_write`, `ahu_${floor}`, "status_write", 1, extra);
    pushMsg(messages, `building/ahu/${floor}/humidity`, `ahu_${floor}`, "humidity", humidity, extra);
    pushMsg(messages, `building/ahu/${floor}/alarm`, `ahu_${floor}`, "alarm", ahuAlarm, extra);
    pushMsg(messages, `building/ahu/${floor}/power`, `ahu_${floor}`, "power", ahuPower, extra);
}

// ------------------------------
// 6) VAV Control Points (16 x 3 = 48)
//    4 per floor
// ------------------------------
for (let floor = 1; floor <= 4; floor++) {
    const zoneLoad = clamp(loadFraction * zoneBias[floor - 1], 0.2, 1.0);

    for (let v = 1; v <= 4; v++) {
        const vavIndex = (floor - 1) * 4 + v;

        const damperPos = Number(clamp(72 + zoneLoad * 18 + Math.random() * 5, 70, 98).toFixed(2));
        const airflow = Number(clamp(850 + zoneLoad * 140 + Math.random() * 40, 800, 1100).toFixed(2));
        const damperCmd = Number(clamp(damperPos + (Math.random() * 4 - 2), 70, 98).toFixed(2));

        const extra = {
            group: "VAV Control Points",
            floor: floor,
            equipment_index: vavIndex
        };

        pushMsg(messages, `building/vav/${vavIndex}/damper_position`, `vav_${vavIndex}`, "damper_position", damperPos, extra);
        pushMsg(messages, `building/vav/${vavIndex}/air_flow_rate`, `vav_${vavIndex}`, "air_flow_rate", airflow, extra);
        pushMsg(messages, `building/vav/${vavIndex}/damper_control`, `vav_${vavIndex}`, "damper_control", damperCmd, extra);
    }
}

// ------------------------------
// 7) IAQ Sensor Points (8 x 4 = 32)
//    2 per floor
// ------------------------------
for (let floor = 1; floor <= 4; floor++) {
    const zoneLoad = clamp(loadFraction * zoneBias[floor - 1], 0.2, 1.0);

    for (let s = 1; s <= 2; s++) {
        const iaqIndex = (floor - 1) * 2 + s;

        const temperature = Number(clamp(24.2 + zoneLoad * 0.8 + (Math.random() * 0.3 - 0.15), 24.0, 25.6).toFixed(2));
        const humidity = Number(clamp(58 + zoneLoad * 5 + Math.random() * 2, 58, 66).toFixed(2));
        const co2 = Number(clamp(780 + zoneLoad * 120 + Math.random() * 40, 780, 980).toFixed(2));
        const pm25 = Number(clamp(14 + zoneLoad * 4 + Math.random() * 2, 12, 24).toFixed(2));

        const extra = {
            group: "IAQ Sensor Points",
            floor: floor,
            equipment_index: iaqIndex
        };

        pushMsg(messages, `building/iaq/${iaqIndex}/temperature`, `iaq_${iaqIndex}`, "temperature", temperature, extra);
        pushMsg(messages, `building/iaq/${iaqIndex}/humidity`, `iaq_${iaqIndex}`, "humidity", humidity, extra);
        pushMsg(messages, `building/iaq/${iaqIndex}/co2`, `iaq_${iaqIndex}`, "co2", co2, extra);
        pushMsg(messages, `building/iaq/${iaqIndex}/pm25`, `iaq_${iaqIndex}`, "pm25", pm25, extra);
    }
}

// ------------------------------
// 8) Digital Power Meter Points (21 units x 5 = 105)
// ------------------------------

// Totals
const totalChillerPower = Number(chillerPowers.reduce((a, b) => a + b, 0).toFixed(2));
const totalCHWPPower = Number(chwpPowers.reduce((a, b) => a + b, 0).toFixed(2));
const totalCDPPower = Number(cdpPowers.reduce((a, b) => a + b, 0).toFixed(2));
const totalCTPower = Number(ctPowers.reduce((a, b) => a + b, 0).toFixed(2));
const totalAHUPower = Number(ahuPowers.reduce((a, b) => a + b, 0).toFixed(2));

// Misc building power (lighting, plugs, elevators etc.)
const miscBuildingPower = Number(clamp(65 + loadFraction * 35 + Math.random() * 8, 65, 110).toFixed(2));
const totalBuildingPower = Number((totalChillerPower + totalCHWPPower + totalCDPPower + totalCTPower + totalAHUPower + miscBuildingPower).toFixed(2));

const voltage = Number(clamp(400 + Math.random() * 8, 398, 410).toFixed(2));
const current = Number((totalBuildingPower * 1000 / (Math.sqrt(3) * voltage * 0.92)).toFixed(2));
const pf = Number(clamp(0.90 + Math.random() * 0.03, 0.90, 0.95).toFixed(3));



// Main Building Meter (1)
pushMsg(messages, "building/meter/main/voltage_LL_average", "main_meter_1", "voltage_LL_average", voltage, {
    group: "Digital Power Meter Points",
    floor: null
});
pushMsg(messages, "building/meter/main/current", "main_meter_1", "current", current, {
    group: "Digital Power Meter Points",
    floor: null
});
pushMsg(messages, "building/meter/main/power", "main_meter_1", "power", totalBuildingPower, {
    group: "Digital Power Meter Points",
    floor: null
});

pushMsg(messages, "building/meter/main/power_factor", "main_meter_1", "power_factor", pf, {
    group: "Digital Power Meter Points",
    floor: null
});

// Floor Sub-Meters (4)
for (let floor = 1; floor <= 4; floor++) {
    const floorLoadShare = Number((miscBuildingPower / 4 + Math.random() * 3).toFixed(2));
    const fPower = Number((floorPowers[floor - 1] + floorLoadShare).toFixed(2));
    const fVoltage = Number(clamp(399 + Math.random() * 7, 398, 410).toFixed(2));
    const fCurrent = Number((fPower * 1000 / (Math.sqrt(3) * fVoltage * 0.92)).toFixed(2));
    floorMeterPowers[floor - 1] = fPower;



    pushMsg(messages, `building/meter/floor/${floor}/voltage_LL_average`, `floor_meter_${floor}`, "voltage_LL_average", fVoltage, {
        group: "Digital Power Meter Points",
        floor: floor
    });
    pushMsg(messages, `building/meter/floor/${floor}/current`, `floor_meter_${floor}`, "current", fCurrent, {
        group: "Digital Power Meter Points",
        floor: floor
    });
    pushMsg(messages, `building/meter/floor/${floor}/power`, `floor_meter_${floor}`, "power", fPower, {
        group: "Digital Power Meter Points",
        floor: floor
    });

    pushMsg(messages, `building/meter/floor/${floor}/power_factor`, `floor_meter_${floor}`, "power_factor", pf, {
        group: "Digital Power Meter Points",
        floor: floor
    });
}

// Chiller Sub-Meters (3)
for (let i = 1; i <= 3; i++) {
    const p = chillerPowers[i - 1];


    pushMsg(messages, `building/meter/chiller/${i}/voltage_LL_average`, `chiller_meter_${i}`, "voltage_LL_average", voltage, {
        group: "Digital Power Meter Points",
        floor: null
    });
    pushMsg(messages, `building/meter/chiller/${i}/current`, `chiller_meter_${i}`, "current", Number((p * 1000 / (Math.sqrt(3) * voltage * 0.92)).toFixed(2)), {
        group: "Digital Power Meter Points",
        floor: null
    });
    pushMsg(messages, `building/meter/chiller/${i}/power`, `chiller_meter_${i}`, "power", p, {
        group: "Digital Power Meter Points",
        floor: null
    });

    pushMsg(messages, `building/meter/chiller/${i}/power_factor`, `chiller_meter_${i}`, "power_factor", pf, {
        group: "Digital Power Meter Points",
        floor: null
    });
}

// CHP Sub-Meters (3)
for (let i = 1; i <= 3; i++) {
    const p = chwpPowers[i - 1];


    pushMsg(messages, `building/meter/chwp/${i}/voltage_LL_average`, `chwp_meter_${i}`, "voltage_LL_average", voltage, {
        group: "Digital Power Meter Points",
        floor: null
    });
    pushMsg(messages, `building/meter/chwp/${i}/current`, `chwp_meter_${i}`, "current", Number((p * 1000 / (Math.sqrt(3) * voltage * 0.92)).toFixed(2)), {
        group: "Digital Power Meter Points",
        floor: null
    });
    pushMsg(messages, `building/meter/chwp/${i}/power`, `chwp_meter_${i}`, "power", p, {
        group: "Digital Power Meter Points",
        floor: null
    });

    pushMsg(messages, `building/meter/chwp/${i}/power_factor`, `chwp_meter_${i}`, "power_factor", pf, {
        group: "Digital Power Meter Points",
        floor: null
    });
}

// CDP Sub-Meters (3)
for (let i = 1; i <= 3; i++) {
    const p = cdpPowers[i - 1];


    pushMsg(messages, `building/meter/cdp/${i}/voltage_LL_average`, `cdp_meter_${i}`, "voltage_LL_average", voltage, {
        group: "Digital Power Meter Points",
        floor: null
    });
    pushMsg(messages, `building/meter/cdp/${i}/current`, `cdp_meter_${i}`, "current", Number((p * 1000 / (Math.sqrt(3) * voltage * 0.92)).toFixed(2)), {
        group: "Digital Power Meter Points",
        floor: null
    });
    pushMsg(messages, `building/meter/cdp/${i}/power`, `cdp_meter_${i}`, "power", p, {
        group: "Digital Power Meter Points",
        floor: null
    });

    pushMsg(messages, `building/meter/cdp/${i}/power_factor`, `cdp_meter_${i}`, "power_factor", pf, {
        group: "Digital Power Meter Points",
        floor: null
    });
}

// CT Sub-Meters (3)
for (let i = 1; i <= 3; i++) {
    const p = ctPowers[i - 1];


    pushMsg(messages, `building/meter/ct/${i}/voltage_LL_average`, `ct_meter_${i}`, "voltage_LL_average", voltage, {
        group: "Digital Power Meter Points",
        floor: null
    });
    pushMsg(messages, `building/meter/ct/${i}/current`, `ct_meter_${i}`, "current", Number((p * 1000 / (Math.sqrt(3) * voltage * 0.92)).toFixed(2)), {
        group: "Digital Power Meter Points",
        floor: null
    });
    pushMsg(messages, `building/meter/ct/${i}/power`, `ct_meter_${i}`, "power", p, {
        group: "Digital Power Meter Points",
        floor: null
    });

    pushMsg(messages, `building/meter/ct/${i}/power_factor`, `ct_meter_${i}`, "power_factor", pf, {
        group: "Digital Power Meter Points",
        floor: null
    });
}

// AHU Sub-Meters (4)
for (let i = 1; i <= 4; i++) {
    const p = ahuPowers[i - 1];


    pushMsg(messages, `building/meter/ahu/${i}/voltage_LL_average`, `ahu_meter_${i}`, "voltage_LL_average", voltage, {
        group: "Digital Power Meter Points",
        floor: i
    });
    pushMsg(messages, `building/meter/ahu/${i}/current`, `ahu_meter_${i}`, "current", Number((p * 1000 / (Math.sqrt(3) * voltage * 0.92)).toFixed(2)), {
        group: "Digital Power Meter Points",
        floor: i
    });
    pushMsg(messages, `building/meter/ahu/${i}/power`, `ahu_meter_${i}`, "power", p, {
        group: "Digital Power Meter Points",
        floor: i
    });

    pushMsg(messages, `building/meter/ahu/${i}/power_factor`, `ahu_meter_${i}`, "power_factor", pf, {
        group: "Digital Power Meter Points",
        floor: i
    });
}

// =====================================================
// FULL SUMMARY (per-device, grouped exactly by spec table)
// =====================================================

const chillerDevices = [
    { key: "chiller_1", idx: 1 },
