    pushMsg(messages, `building/ahu/${floor}/status_read`, `ahu_${floor}`, "status_read", 1, extra);
    pushMsg(messages, `building/ahu/${floor}/status_write`, `ahu_${floor}`, "status_write", 1, extra);
    pushMsg(messages, `building/ahu/${floor}/humidity`, `ahu_${floor}`, "humidity", humidity, extra);
    pushMsg(messages, `building/ahu/${floor}/alarm`, `ahu_${floor}`, "alarm", ahuAlarm, extra);
    pushMsg(messages, `building/ahu/${floor}/power`, `ahu_${floor}`, "power", ahuPower, extra);
}

// ------------------------------
// 6) VAV Control Points (16 x 3 = 48)
