// 2) Chiller Monitoring Points (3 x 13 = 39)
// ------------------------------
for (let i = 1; i <= 3; i++) {
    let isActive = 1;
    let statusWrite = 1;
    let alarm = 0;
    let effectiveRT = Number((totalCoolingRT / effectiveRunningChillers).toFixed(2));

    // CH-2 trip
    if (i === 2) {
        isActive = 0;
        statusWrite = 0;
        alarm = 1;
        effectiveRT = 0;
    }

    let plr = 0;
    let efficiency = 0;
    let powerKW = 0;
    let evapFlow = 0;
    let satRefrigTempF = 0;
    let approachTempF = 0;
    let percentageRLA = 0;
    let coolingRate = 0;

    if (isActive) {
        plr = clamp(effectiveRT / CHILLER_RATED_RT, 0.22, 1.0);
        efficiency = Number(clamp(
            0.56 + (1 - plr) * 0.08 + Math.random() * 0.02,
            0.54,
            0.72
        ).toFixed(3));

        powerKW = Number(clamp(effectiveRT * efficiency, 70, CHILLER_RATED_KW).toFixed(2));
        evapFlow = Number(clamp(650 + plr * 340 + Math.random() * 20, 0, CHWP_RATED_GPM).toFixed(2));
        satRefrigTempF = Number(clamp(chwSupplyF - rnd(5, 7), 34, 42).toFixed(2));
        approachTempF = Number(clamp(1.8 + Math.random() * 2.0, 1.5, 5.0).toFixed(2));
        percentageRLA = Number((plr * 100).toFixed(2));
        coolingRate = effectiveRT;
    }

    chillerPowers[i - 1] = powerKW;

    const extra = {
        group: "Chiller Monitoring Points",
        floor: null,
        equipment_index: i
    };

    pushMsg(messages, `building/chiller/${i}/evap_leaving_water_temperature`, `chiller_${i}`, "evap_leaving_water_temperature", isActive ? chwSupplyF : 0, extra);
    pushMsg(messages, `building/chiller/${i}/evap_entering_water_temperature`, `chiller_${i}`, "evap_entering_water_temperature", isActive ? chwReturnF : 0, extra);
    pushMsg(messages, `building/chiller/${i}/evap_water_flow_rate`, `chiller_${i}`, "evap_water_flow_rate", evapFlow, extra);
    pushMsg(messages, `building/chiller/${i}/evap_sat_refrig_temperature`, `chiller_${i}`, "evap_sat_refrig_temperature", satRefrigTempF, extra);
    pushMsg(messages, `building/chiller/${i}/evap_water_delta_temperature`, `chiller_${i}`, "evap_water_delta_temperature", isActive ? deltaTF : 0, extra);
    pushMsg(messages, `building/chiller/${i}/evap_approach_temperature`, `chiller_${i}`, "evap_approach_temperature", approachTempF, extra);
    pushMsg(messages, `building/chiller/${i}/status_read`, `chiller_${i}`, "status_read", isActive, extra);
    pushMsg(messages, `building/chiller/${i}/status_write`, `chiller_${i}`, "status_write", statusWrite, extra);
    pushMsg(messages, `building/chiller/${i}/power`, `chiller_${i}`, "power", powerKW, extra);
    pushMsg(messages, `building/chiller/${i}/alarm`, `chiller_${i}`, "alarm", alarm, extra);
    pushMsg(messages, `building/chiller/${i}/percentage_rla`, `chiller_${i}`, "percentage_rla", percentageRLA, extra);
    pushMsg(messages, `building/chiller/${i}/efficiency`, `chiller_${i}`, "efficiency", efficiency, extra);
    pushMsg(messages, `building/chiller/${i}/cooling_rate`, `chiller_${i}`, "cooling_rate", coolingRate, extra);
}

// ------------------------------
// 3) Pump & Cooling Tower Points (9 x 7 = 63)
// ------------------------------
for (let i = 1; i <= 3; i++) {
    // CH-2-associated pumps/tower stop, CH-1 and CH-3 run
    const isActive = (i === 1 || i === 3) ? 1 : 0;

    // CHWP
    let chwpFreq = 0;
    let chwpPower = 0;
    let chwpEff = 0;

    if (isActive) {
        chwpFreq = Number(clamp(rnd(48, 57), 0, 60).toFixed(2));
        chwpPower = Number((CHWP_RATED_KW * Math.pow(chwpFreq / 60, 3)).toFixed(2));
        chwpEff = Number((0.73 + Math.random() * 0.03).toFixed(3));
    }

    chwpPowers[i - 1] = chwpPower;

    let extra = { group: "Pump & Cooling Tower Points", floor: null, equipment_index: i };
    pushMsg(messages, `building/chwp/${i}/status_read`, `chwp_${i}`, "status_read", isActive, extra);
    pushMsg(messages, `building/chwp/${i}/status_write`, `chwp_${i}`, "status_write", isActive, extra);
    pushMsg(messages, `building/chwp/${i}/alarm`, `chwp_${i}`, "alarm", 0, extra);
    pushMsg(messages, `building/chwp/${i}/frequency_read`, `chwp_${i}`, "frequency_read", chwpFreq, extra);
    pushMsg(messages, `building/chwp/${i}/frequency_write`, `chwp_${i}`, "frequency_write", chwpFreq, extra);
    pushMsg(messages, `building/chwp/${i}/power`, `chwp_${i}`, "power", chwpPower, extra);
    pushMsg(messages, `building/chwp/${i}/efficiency`, `chwp_${i}`, "efficiency", chwpEff, extra);

    // CDP
    let cdpFreq = 0;
    let cdpPower = 0;
    let cdpEff = 0;

    if (isActive) {
        cdpFreq = Number(clamp(rnd(46, 55), 0, 60).toFixed(2));
        cdpPower = Number((CDP_RATED_KW * Math.pow(cdpFreq / 60, 3)).toFixed(2));
        cdpEff = Number((0.72 + Math.random() * 0.03).toFixed(3));
    }

    cdpPowers[i - 1] = cdpPower;

    pushMsg(messages, `building/cdp/${i}/status_read`, `cdp_${i}`, "status_read", isActive, extra);
    pushMsg(messages, `building/cdp/${i}/status_write`, `cdp_${i}`, "status_write", isActive, extra);
    pushMsg(messages, `building/cdp/${i}/alarm`, `cdp_${i}`, "alarm", 0, extra);
    pushMsg(messages, `building/cdp/${i}/frequency_read`, `cdp_${i}`, "frequency_read", cdpFreq, extra);
    pushMsg(messages, `building/cdp/${i}/frequency_write`, `cdp_${i}`, "frequency_write", cdpFreq, extra);
    pushMsg(messages, `building/cdp/${i}/power`, `cdp_${i}`, "power", cdpPower, extra);
    pushMsg(messages, `building/cdp/${i}/efficiency`, `cdp_${i}`, "efficiency", cdpEff, extra);

    // CT
    let ctFreq = 0;
    let ctPower = 0;
    let ctEff = 0;

    if (isActive) {
        ctFreq = Number(clamp(rnd(40, 50), 0, 60).toFixed(2));
        ctPower = Number((CT_CELL_RATED_KW * Math.pow(ctFreq / 60, 3) * 2).toFixed(2));
        ctEff = Number((0.69 + Math.random() * 0.04).toFixed(3));
    }

    ctPowers[i - 1] = ctPower;

    pushMsg(messages, `building/ct/${i}/status_read`, `ct_${i}`, "status_read", isActive, extra);
    pushMsg(messages, `building/ct/${i}/status_write`, `ct_${i}`, "status_write", isActive, extra);
    pushMsg(messages, `building/ct/${i}/alarm`, `ct_${i}`, "alarm", 0, extra);
    pushMsg(messages, `building/ct/${i}/frequency_read`, `ct_${i}`, "frequency_read", ctFreq, extra);
    pushMsg(messages, `building/ct/${i}/frequency_write`, `ct_${i}`, "frequency_write", ctFreq, extra);
    pushMsg(messages, `building/ct/${i}/power`, `ct_${i}`, "power", ctPower, extra);
    pushMsg(messages, `building/ct/${i}/efficiency`, `ct_${i}`, "efficiency", ctEff, extra);
}

