        total_ct_power_kw: totalCTPower,
        total_ahu_power_kw: totalAHUPower,
        total_building_power_kw: totalBuildingPower,
        avg_iaq_co2_ppm: Number(avg(iaqDevices.map(d => getValue(messages, `building/iaq/${d.idx}/co2`))).toFixed(2)),
        avg_ahu_room_temp_c: Number(avg(ahuDevices.map(d => getValue(messages, `building/ahu/${d.idx}/room_temperature`))).toFixed(2)),
        payload_count: messages.length
    }
};

// =====================================================
// Compliance Check
