    }
};

compliance_check.pass_groups =
    compliance_check.expected_groups["Chiller Monitoring Points"] === compliance_check.actual_groups["Chiller Monitoring Points"] &&
    compliance_check.expected_groups["Pump & Cooling Tower Points"] === compliance_check.actual_groups["Pump & Cooling Tower Points"] &&
    compliance_check.expected_groups["Motorized Valve Points"] === compliance_check.actual_groups["Motorized Valve Points"] &&
    compliance_check.expected_groups["AHU Monitoring Points"] === compliance_check.actual_groups["AHU Monitoring Points"] &&
    compliance_check.expected_groups["VAV Control Points"] === compliance_check.actual_groups["VAV Control Points"] &&
