// =====================================================
// Energy Accumulator (Reset-safe + Seeded)
// Input from scenario function:
//   msg.payload            = messages array (without energy points)
//   msg.summary            = summary object
//   msg.compliance         = compliance object
//   msg.energy_inputs      = power map for all digital meters
//
// Optional controls:
//   msg.reset_energy_store = true   -> reset accumulated energy to seeded baseline
//
// Output:
//   output 1 = messages array (energy points added back)
//   output 2 = summary
//   output 3 = compliance
// =====================================================

// ------------------------------
// Time / Keys
// ------------------------------
const ENERGY_STORE_KEY = "hvac_energy_store_seeded_v1";
const LAST_MS_KEY = "energy_last_ms_seeded_v1";

let nowMs = Date.now();
let lastMs = flow.get(LAST_MS_KEY) || nowMs;
let intervalSec = (nowMs - lastMs) / 1000;

// กันค่าเพี้ยนตอน deploy/restart
if (intervalSec <= 0) intervalSec = 1;
if (intervalSec > 600) intervalSec = 5;

flow.set(LAST_MS_KEY, nowMs);

// ------------------------------
// Seed baseline from your current realistic values
// ------------------------------
const seededEnergyStore = {
    main_meter_1: 100000.33,

    floor_meter_1: 10000.01,
    floor_meter_2: 20000.01,
    floor_meter_3: 30000.01,
    floor_meter_4: 40000.01,

    chiller_meter_1: 20000.07,
    chiller_meter_2: 40000.07,
    chiller_meter_3: 60000.07,

    chwp_meter_1: 5000.01,
    chwp_meter_2: 10000.01,
    chwp_meter_3: 15000.01,

    cdp_meter_1: 6000.01,
    cdp_meter_2: 12000.01,
    cdp_meter_3: 18000.01,

    ct_meter_1: 4000.00,
    ct_meter_2: 8000.00,
    ct_meter_3: 12000.00,

    ahu_meter_1: 3000.01,
    ahu_meter_2: 6000.01,
    ahu_meter_3: 9000.00,
    ahu_meter_4: 12000.01
};

// ------------------------------
// Meter list
// ------------------------------
const meterKeys = Object.keys(seededEnergyStore);

// ------------------------------
// Clone inputs
// ------------------------------
let messages = Array.isArray(msg.payload) ? [...msg.payload] : [];
let summary = msg.summary || {};
let compliance = msg.compliance || {};
let energyInputs = msg.energy_inputs || {};

// ------------------------------
// Helpers
// ------------------------------
function cloneSeedStore() {
    return JSON.parse(JSON.stringify(seededEnergyStore));
}

function normalizeStore(store) {
    const out = {};
    meterKeys.forEach(k => {
        const v = Number(store?.[k]);
        out[k] = Number.isNaN(v) ? seededEnergyStore[k] : v;
    });
    return out;
}

function buildEnergyTopic(meterKey) {
    if (meterKey === "main_meter_1") return "building/meter/main/energy";

    const parts = meterKey.split("_");
    if (parts.length === 3 && parts[1] === "meter") {
        return `building/meter/${parts[0]}/${parts[2]}/energy`;
    }

    return `building/meter/${meterKey}/energy`;
}

function getMeterFloor(meterKey) {
    if (meterKey.startsWith("floor_meter_")) {
        return Number(meterKey.split("_")[2]);
    }
    if (meterKey.startsWith("ahu_meter_")) {
        return Number(meterKey.split("_")[2]);
    }
    return null;
}

function parsePayload(m) {
    if (!m || !m.payload) return null;
    try {
        return JSON.parse(m.payload);
    } catch (e) {
        return null;
    }
}

function upsertEnergyPoint(arr, meterKey, energyValue) {
    const idx = arr.findIndex(m => {
        const p = parsePayload(m);
        return p && p.device === meterKey && p.point === "energy";
    });

    const energyMsg = {
        topic: buildEnergyTopic(meterKey),
        payload: JSON.stringify({
            timestamp: new Date().toISOString(),
            device: meterKey,
            point: "energy",
            value: Number(energyValue.toFixed(2)),
            group: "Digital Power Meter Points",
            floor: getMeterFloor(meterKey)
        })
    };

    if (idx >= 0) {
        arr[idx] = energyMsg;
    } else {
        arr.push(energyMsg);
    }
}

function getValueFromMessages(arr, topic) {
    const item = arr.find(m => m.topic === topic);
    if (!item) return null;

    const p = parsePayload(item);
    if (!p) return null;

    return p.value;
}

function buildGroupSummary(arr, devices, points, topicBuilder) {
    const result = {};
    devices.forEach(deviceObj => {
        const devKey = deviceObj.key;
        result[devKey] = {};
        points.forEach(point => {
            result[devKey][point] = getValueFromMessages(arr, topicBuilder(deviceObj, point));
        });
    });
    return result;
}

// ------------------------------
// Meter devices for summary rebuild
// ------------------------------
const meterDevices = [
    { key: "main_meter_1", type: "main", idx: 1 },

    { key: "floor_meter_1", type: "floor", idx: 1 },
    { key: "floor_meter_2", type: "floor", idx: 2 },
    { key: "floor_meter_3", type: "floor", idx: 3 },
    { key: "floor_meter_4", type: "floor", idx: 4 },

    { key: "chiller_meter_1", type: "chiller", idx: 1 },
    { key: "chiller_meter_2", type: "chiller", idx: 2 },
    { key: "chiller_meter_3", type: "chiller", idx: 3 },

    { key: "chwp_meter_1", type: "chwp", idx: 1 },
    { key: "chwp_meter_2", type: "chwp", idx: 2 },
    { key: "chwp_meter_3", type: "chwp", idx: 3 },

    { key: "cdp_meter_1", type: "cdp", idx: 1 },
    { key: "cdp_meter_2", type: "cdp", idx: 2 },
    { key: "cdp_meter_3", type: "cdp", idx: 3 },

    { key: "ct_meter_1", type: "ct", idx: 1 },
    { key: "ct_meter_2", type: "ct", idx: 2 },
    { key: "ct_meter_3", type: "ct", idx: 3 },

    { key: "ahu_meter_1", type: "ahu", idx: 1 },
    { key: "ahu_meter_2", type: "ahu", idx: 2 },
    { key: "ahu_meter_3", type: "ahu", idx: 3 },
    { key: "ahu_meter_4", type: "ahu", idx: 4 }
];

// ------------------------------
// Load / Reset context
// ------------------------------
let energyStore = flow.get(ENERGY_STORE_KEY);

if (msg.reset_energy_store === true) {
    energyStore = cloneSeedStore();
    flow.set(ENERGY_STORE_KEY, energyStore);
    flow.set(LAST_MS_KEY, nowMs);
} else if (!energyStore) {
    energyStore = cloneSeedStore();
} else {
    energyStore = normalizeStore(energyStore);
}

// ------------------------------
// Accumulate energy
// ------------------------------
meterKeys.forEach((meterKey) => {
    const power = Number(energyInputs[meterKey] || 0);

    // ถ้า power > 0 ค่อยสะสม
    // ถ้า power = 0 ให้คงค่าเดิม
    if (!Number.isNaN(power) && power > 0) {
        energyStore[meterKey] += power * (intervalSec / 3600);
    }

    // กันติดลบเผื่อกรณีมีค่าเพี้ยนจากภายนอก
    if (energyStore[meterKey] < 0) {
        energyStore[meterKey] = seededEnergyStore[meterKey];
    }

    upsertEnergyPoint(messages, meterKey, energyStore[meterKey]);
});

// save store
flow.set(ENERGY_STORE_KEY, energyStore);

// ------------------------------
// Update summary
// ------------------------------
if (!summary.extra) summary.extra = {};
summary.extra.energy_store_snapshot = { ...energyStore };
summary.extra.payload_count = messages.length;
summary.extra.energy_interval_sec = intervalSec;
summary.extra.energy_seed_mode = "seeded_baseline";

summary["Digital Power Meter Points"] = buildGroupSummary(
    messages,
    meterDevices,
    ["voltage_LL_average", "current", "power", "energy", "power_factor"],
    (d, p) => {
        if (d.type === "main") return `building/meter/main/${p}`;
        return `building/meter/${d.type}/${d.idx}/${p}`;
    }
);

// ------------------------------
// Update compliance
// ------------------------------
if (compliance && compliance.expected_message_count) {
    compliance.actual_message_count = messages.length;
    compliance.pass_total_count = messages.length === compliance.expected_message_count;
}

if (compliance && compliance.expected_groups) {
    compliance.actual_groups = {
        "Chiller Monitoring Points": messages.filter(m => m.topic.includes("/chiller/") && !m.topic.includes("/meter/")).length,
        "Pump & Cooling Tower Points":
            messages.filter(m => m.topic.includes("/chwp/") && !m.topic.includes("/meter/")).length +
            messages.filter(m => m.topic.includes("/cdp/") && !m.topic.includes("/meter/")).length +
            messages.filter(m => m.topic.includes("/ct/") && !m.topic.includes("/meter/")).length,
        "Motorized Valve Points": messages.filter(m => m.topic.includes("/mv/")).length,
        "AHU Monitoring Points": messages.filter(m => m.topic.includes("/ahu/") && !m.topic.includes("/meter/")).length,
        "VAV Control Points": messages.filter(m => m.topic.includes("/vav/")).length,
        "IAQ Sensor Points": messages.filter(m => m.topic.includes("/iaq/")).length,
        "Outdoor Weather Station Points": messages.filter(m => m.topic.includes("/weather/")).length,
        "Digital Power Meter Points": messages.filter(m => m.topic.includes("/meter/")).length
    };

    compliance.pass_groups =
        compliance.expected_groups["Chiller Monitoring Points"] === compliance.actual_groups["Chiller Monitoring Points"] &&
        compliance.expected_groups["Pump & Cooling Tower Points"] === compliance.actual_groups["Pump & Cooling Tower Points"] &&
        compliance.expected_groups["Motorized Valve Points"] === compliance.actual_groups["Motorized Valve Points"] &&
        compliance.expected_groups["AHU Monitoring Points"] === compliance.actual_groups["AHU Monitoring Points"] &&
        compliance.expected_groups["VAV Control Points"] === compliance.actual_groups["VAV Control Points"] &&
        compliance.expected_groups["IAQ Sensor Points"] === compliance.actual_groups["IAQ Sensor Points"] &&
        compliance.expected_groups["Outdoor Weather Station Points"] === compliance.actual_groups["Outdoor Weather Station Points"] &&
        compliance.expected_groups["Digital Power Meter Points"] === compliance.actual_groups["Digital Power Meter Points"];
}

// ------------------------------
// Return
// ------------------------------
return [
    { payload: messages },
    { payload: summary },
    { payload: compliance }
];

// หลัง split ตอนนี้ msg.payload มีโครงแบบ:
// {
//   topic: "...",
//   payload: "{\"timestamp\":\"...\"}"
// }

if (!msg.payload || !msg.payload.topic) {
    node.error("Missing payload.topic", msg);
    return null;
}

msg.topic = msg.payload.topic;

if (typeof msg.payload.payload === "string") {
    try {
        msg.payload = JSON.parse(msg.payload.payload);
    } catch (e) {
        node.error("Invalid JSON in payload.payload", msg);
        return null;
    }
} else {
    msg.payload = msg.payload.payload;
}

return msg;

let now = new Date();
let hour = now.getHours();
let day = now.getDay(); // 0 = Sunday, 1 = Monday, ..., 6 = Saturday

let isWeekday = day >= 1 && day <= 5; // Mon-Fri
let isWeekend = day === 0 || day === 6; // Sat-Sun

if (hour >= 9 && hour < 17) {
    if (isWeekday) {
        msg.scenario = "peak";
    } else if (isWeekend) {
        msg.scenario = "medium";
    }
} else {
    msg.scenario = "night";
}

return msg;
